(function() {
    /*======== 版本更新日志 ========*/
    /*
     * 作者：sjshb57
     * GitHub：https://github.com/sjshb57/legado-57
     *
     * [v2.6.0] 第二十七次修改 - 优化代码
     * - 修正错误，同并删除大量冗余注释示例
     * - 移除冗余代码 删除 hasSpace检测逻辑
     * - 修复当数字标题时无法触发规则的问题
     * - 修复标题前部分标点无法正常移除问题
     */

    // ========= 1. 功能文档 =========
    /*
     * 功能概述：
     * 本脚本是一个高级中文数字标题转换工具，专门用于处理各种格式的中文数字标题，
     * 将其转换为统一的阿拉伯数字格式，同时提供多种智能处理选项。
     *
     * 主要功能：
     * 1. 全面支持简繁体中文数字转换（零-萬）
     * 2. 支持繁体大写数字（壹貳參等）
     * 3. 智能空格处理（自动补全章节号与内容间的空格）
     * 4. 标点符号规范化（移除标题末尾冗余标点）
     * 5. 非章节标题句号清理（『请。假。』→『请假』）
     * 6. 特殊章节处理（『第零章』→『序章』）
     * 7. 支持纯数字标题转换（『1 内容』→『第1章 内容』）
     * 8. 无标识符标题兼容（『第一百标题』→『第100章 标题』）
     * 9. 多章节标识符适配（章/节/回/集等）
     * 10. 灵活的配置系统（动态调整空格/标点等规则）
     *
     * 典型输入输出示例：
     * 输入 → 输出
     * ----------------------------------------
     * 基础数字转换
     * 『第一章 内容』  → 『第1章 内容』
     * 『第壹佰贰拾叁节』→ 『第123节』
     * 『第伍萬陆仟柒佰捌拾篇』→ 『第56780篇』
     *
     * 零值与特殊格式
     * 『第零回 内容』 → 『序回 内容』（convertZeroToPreface=true时）
     * 『第〇章 空白』 → 『第0章 空白』（convertZeroToPreface=false时）
     * 『第一百标题』  → 『第100章 标题』（无标识符自动补defaultSuffix）
     *
     * 空格与标点规范
     * 『第1章内容』   → 『第1章 内容』（自动补空格）
     * 『第1章：简介』 → 『第1章：简介』（中文标点前不补空格）
     * 『请假。』      → 『请假』（移除非章节标题中的句号）
     *
     * 纯数字标题处理
     * 『123』        → 『第123章』
     * 『456内容』    → 『第456章 内容』
     * 『01 测试』    → 『第01章 测试』
     *
     * 混合与边界示例
     * 『第1章　内容』 → 『第1章　内容』（保留全角空格）
     * 『第零章测试』  → 『序章 测试』（零值转换+自动补空格）
     * 『第100章.』   → 『第100章』（末尾标点清理）
     */

    // ========= 2. 配置系统 =========
    /*
     * 所有功能行为都可通过 Config 对象进行精细控制。
     *
     * 配置项说明：
     *
     * removePunctuation {boolean} 默认 true
     *   是否移除章节标题（以『第』开头）末尾的标点（。！？.,：；等）
     *   示例：『第一章。』→『第1章』（true时）
     *
     * autoAddSpace {boolean} 默认 true
     *   是否在章节号和内容之间自动添加空格
     *   示例：『第1章内容』→『第1章 内容』（true时）
     *
     * convertZeroToPreface {boolean} 默认 false
     *   是否将第零章/第零回等转换为序章/序回
     *   示例：『第零回』→『序回』（true时）
     *
     * maxCacheSize {number} 默认 100
     *   正则缓存的最大条目数，防止内存无限增长
     *
     * defaultSuffix {string} 默认 '章'
     *   当标题无章节标识符时使用的默认后缀
     *   示例：『第一百标题』→『第100章 标题』
     *   设置为『篇』时：→『第100篇 标题』
     *
     * removePeriods {boolean} 默认 true
     *   是否移除非章节标题（不以『第』开头）中的所有句号（。和.）
     *   示例：『内容。』→『内容』（true时）
     *
     * 动态修改配置：
     * Config.update({ autoAddSpace: false });
     */
    const Config = {
        removePunctuation: true, // 是否移除章节标题末尾标点
        autoAddSpace: true, // 是否自动添加空格
        convertZeroToPreface: false, // 是否将零值转换为"序"
        maxCacheSize: 100, // 正则缓存最大条目数
        defaultSuffix: '章', // 无标识符时的默认后缀
        removePeriods: true, // 是否移除非章节标题中的句号

        /*
         * 动态更新配置参数，只更新传入的字段，其余保持原值。
         * 示例：Config.update({ autoAddSpace: false });
         */
        update: function(newConfig) {
            Object.assign(this, newConfig);
        }
    };

    // ====== 3. 正则表达式系统 ======
    /*
     * Regex 对象封装所有预编译的正则表达式，避免重复编译，提升性能。
     *
     * patterns 中各正则说明：
     *
     * chinesePunctuation  /^[：、，；？！（）「」【】]/
     *   检测内容是否以中文标点开头，用于阻止在标点前自动插入空格。
     *   示例：『：内容』→ 匹配，不补空格
     *
     * chapter  /^第(\d+|[中文数字]+)([章节回集卷部篇话讲段]?)(.*)/
     *   主匹配正则，提取章节标题的三个部分：
     *     第1组：章节数字，优先匹配阿拉伯数字，其次匹配中文数字（支持简繁体及财务大写）
     *     第2组：章节标识符（可选，如章/节/回/集等）
     *     第3组：标题内容
     *   示例：
     *     『第1章 内容』        → ['1', '章', ' 内容']
     *     『第壹佰贰拾叁节 内容』→ ['壹佰贰拾叁', '节', ' 内容']
     *     『第一百标题』        → ['一百', '', '标题']
     *
     * digitalChapter  /^(\d+)\s*(.*)/
     *   匹配纯数字开头的标题：
     *     第1组：数字部分
     *     第2组：剩余内容（\s* 已消耗数字后的空格）
     *   示例：
     *     『123 内容』→ ['123', '内容']
     *     『456测试』 → ['456', '测试']
     *
     * titlePunctuation  /[。！？.，：；]+$/
     *   匹配标题末尾连续的中英文标点，用于末尾标点清理。
     *   示例：『第1章！』→ 匹配『！』
     *
     * period  /[。.]/g
     *   全局匹配中文和英文句号，用于清理非章节标题中的句号。
     *   示例：『请。假。』→ 全部『。』被匹配并移除
     */
    const Regex = {
        patterns: {
            chinesePunctuation: /^[：、，；？！（）「」【】]/,
            chapter: /^第(\d+|[零〇一二三四五六七八九十百千两万壹贰叁肆伍陆柒捌玖拾佰仟萬貳參陸]+)([章节回集卷部篇话讲段]?)(.*)/,
            digitalChapter: /^(\d+)\s*(.*)/,
            titlePunctuation: /[。.，：；]+$/,
            period: /[。.]/g
        }
    };

    // ======= 4. 数字转换系统 =======
    /*
     * NumberConverter 负责将中文数字字符串转换为阿拉伯数字。
     *
     * map 映射表覆盖：
     *   基础数字：零〇一二两三四五六七八九（含同义词）
     *   单位数字：十百千万（进位单位）
     *   财务大写：壹贰叁肆伍陆柒捌玖拾佰仟萬
     *   繁体数字：貳參陸
     *
     * convert 算法（逐字扫描，O(n) 时间，O(1) 空间）：
     *   维护两个变量：
     *     total - 已完成计算的累计值
     *     temp  - 当前待与进位单位相乘的临时值
     *
     *   规则：
     *   - 遇到进位单位（十/百/千/万）：
     *       temp 若为0（如『十二』的『十』前无数字），按1处理
     *       temp × 单位 → 累加到 total，temp 归零
     *   - 遇到普通数字字符：temp += 数值
     *   - 循环结束后：total + temp 即为最终结果
     *
     *   示例：『貳佰叁拾』
     *     貳(2)→temp=2
     *     佰(100)→temp=2×100=200→total=200，temp=0
     *     叁(3)→temp=3
     *     拾(10)→temp=3×10=30→total=230，temp=0
     *     结果：230
     *
     *   示例：『壹萬伍仟陆佰柒拾捌』
     *     壹→temp=1；萬→total=10000，temp=0
     *     伍→temp=5；仟→total=15000，temp=0
     *     陆→temp=6；佰→total=15600，temp=0
     *     柒→temp=7；拾→total=15670，temp=0
     *     捌→temp=8
     *     结果：15678
     */
    const NumberConverter = {
        map: {
            // 基础数字
            '零': 0,
            '〇': 0,
            '一': 1,
            '二': 2,
            '两': 2,
            '三': 3,
            '四': 4,
            '五': 5,
            '六': 6,
            '七': 7,
            '八': 8,
            '九': 9,
            // 进位单位
            '十': 10,
            '百': 100,
            '千': 1000,
            '万': 10000,
            // 财务大写
            '壹': 1,
            '贰': 2,
            '叁': 3,
            '肆': 4,
            '伍': 5,
            '陆': 6,
            '柒': 7,
            '捌': 8,
            '玖': 9,
            '拾': 10,
            '佰': 100,
            '仟': 1000,
            '萬': 10000,
            // 繁体
            '貳': 2,
            '參': 3,
            '陸': 6
        },

        convert: function(chineseNum) {
            let total = 0;
            let temp = 0;

            for (let i = 0; i < chineseNum.length; i++) {
                const val = this.map[chineseNum[i]];
                if ([10, 100, 1000, 10000].includes(val)) {
                    // 遇到进位单位：temp 为 0 时视为隐含的 1（如『十二』→12）
                    temp = (temp === 0 ? 1 : temp) * val;
                    total += temp;
                    temp = 0;
                } else if (val !== undefined) {
                    temp += val;
                }
            }

            return total + temp;
        }
    };

    // ======== 5. 主处理函数 ========
    /*
     * processTitle(title) - 标题转换主逻辑
     *
     * 处理流程：
     *   ┌─ 以数字开头？──→ 转换为「第N章 内容」格式，返回
     *   │
     *   ├─ 不以「第」开头？──→ 按 removePeriods 配置移除句号，返回
     *   │
     *   ├─ removePunctuation=true？──→ 移除标题末尾标点
     *   │
     *   ├─ chapter 正则匹配失败？──→ 原样返回
     *   │
     *   ├─ 中文数字转换 → 零值处理（convertZeroToPreface）
     *   │
     *   └─ 拼装结果：「第N章[ 内容]」，按需补空格，返回
     */
    function processTitle(title) {

        // --- 步骤1：纯数字标题处理 ---
        // 匹配以数字开头的标题，统一转换为「第N章 内容」格式。
        // 数字与内容之间的前导标点（如「1. 章节名」的点）会被清除。
        const digitalMatch = title.match(Regex.patterns.digitalChapter);
        if (digitalMatch) {
            const [, num, content] = digitalMatch;
            const cleanedContent = content.trim().replace(/^[.。,，]+/, '').trim();
            return cleanedContent ?
                `第${num}${Config.defaultSuffix} ${cleanedContent}` :
                `第${num}${Config.defaultSuffix}`;
        }

        // --- 步骤2：非「第」开头标题处理 ---
        // 不以「第」开头的标题不含章节号，只做句号清理后直接返回。
        // removePeriods=true 时移除标题中所有的中英文句号（。和.）。
        // 注意：此处的 period 正则带 /g 标志，每次调用前需重置 lastIndex。
        if (!title.startsWith('第')) {
            if (Config.removePeriods) {
                Regex.patterns.period.lastIndex = 0;
                return title.replace(Regex.patterns.period, '');
            }
            return title;
        }

        // --- 步骤3：章节标题末尾标点清理 ---
        // 到达此处说明标题以「第」开头（中文数字章节标题）。
        // removePunctuation=true 时移除末尾的标点符号（。！？.,：；等）。
        if (Config.removePunctuation) {
            title = title.replace(Regex.patterns.titlePunctuation, '');
        }

        // --- 步骤4：正则匹配标题各部分 ---
        // 提取中文数字标题的三个组成部分：
        //   chineseNum    - 中文数字字符串（如「壹佰贰拾叁」）
        //   originalSuffix - 章节标识符（如「节」，可能为空字符串）
        //   titlePart     - 标题（如「 内容」，含原始前导空格）
        // 若匹配失败（如「第abc章」），原样返回。
        const match = title.match(Regex.patterns.chapter);
        if (!match) return title;

        const [, chineseNum, originalSuffix, titlePart] = match;

        // originalSuffix 为空说明标题无章节标识符（如「第一百标题」），
        // 使用 Config.defaultSuffix 作为默认后缀。
        let suffix = originalSuffix || Config.defaultSuffix;

        // 清理标题前导的逗号和空白（如「，内容」→「内容」）
        const cleanTitlePart = (titlePart || '').replace(/^[\s.。,，]+/, '').trim();

        // --- 步骤5：数字转换 ---
        // chineseNum 为阿拉伯数字时直接使用，为中文数字时调用 NumberConverter.convert 转换。
        let number = /^\d+$/.test(chineseNum) ? chineseNum : NumberConverter.convert(chineseNum);

        // --- 步骤6：零值特殊处理 ---
        // convertZeroToPreface=true 且转换结果为 0 时，
        // 将「第零章」形式转换为「序章」：number 清空，suffix 前缀加「序」。
        if (number === 0 && Config.convertZeroToPreface) {
            number = '';
            suffix = '序' + suffix;
        }

        // --- 步骤7：空格处理与结果组装 ---
        // 判断是否需要在章节号与标题之间插入空格：
        //   - autoAddSpace=true（配置开启）
        //   - 标题不以中文标点开头（如「：内容」不需补空格）
        //
        // 注意：cleanTitlePart 已通过 replace(/^[\s.。,，]+/, '').trim() 清除了
        //   原标题中章节标识符后的所有前导空格与标点（包括「空格+逗号」等组合），
        //   因此无需再检测原始标题是否含有空格，直接按规则决定是否补空格即可。
        if (cleanTitlePart) {
            const shouldAddSpace = Config.autoAddSpace &&
                !Regex.patterns.chinesePunctuation.test(cleanTitlePart);
            return `第${number}${suffix}${shouldAddSpace ? ' ' : ''}${cleanTitlePart}`;
        }

        // 无标题时直接返回「第N章」格式
        return `第${number}${suffix}`;
    }

    // ========== 执行入口 ==========
    // result 是阅读软件传入的原始标题文本，processTitle 处理后返回转换结果。
    // 整体执行时间受 timeoutMillisecond（3000ms）限制。
    return processTitle(result);
})();
